{
  "formal_minutes": {
    "회의명": "UI Theme Package Release Readiness",
    "프로젝트코드": "PUBLIC_MEETING_SMOKE",
    "참석자": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "주제": "공개 릴리스 목표 시점",
        "결정": "스모크 테스트가 통과하는 경우 금요일 15:00 KST를 공개 릴리스 목표로 한다."
      },
      {
        "주제": "packageName mismatch 대응",
        "결정": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토로 넘어간다."
      }
    ],
    "rejected_proposals": [
      {
        "제안자": "Hara",
        "제안": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "결과": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "주제": "수요일 릴리스 제안",
        "내용": "Seoyeon이 수요일 릴리스를 제안했으나 확정 일정이 아니며 내부 스트레치 목표로만 남았다."
      }
    ],
    "non_decisions": [
      {
        "주제": "README 설치 단계 검토",
        "내용": "목요일까지 가능하면 검토하자는 의견이 있었지만 담당자 지정이나 확정 조치는 없었다."
      },
      {
        "주제": "최종 릴리스 승인 권한",
        "내용": "누가 최종 승인 권한을 가지는지 결정되지 않았다."
      },
      {
        "주제": "수요일 내부 목표의 릴리스 노트 기재 여부",
        "내용": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할지 결론이 나지 않았다."
      }
    ],
    "risks": [
      {
        "위험": "잘못된 tarball 경로",
        "영향": "릴리스 지연 가능"
      },
      {
        "위험": "README 설치 단계의 최신성 부족",
        "영향": "릴리스 노트가 사용자에게 오해를 줄 수 있음"
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "대기",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "대기",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "선행 결과 대기",
      "source_certainty": "확정"
    },
    {
      "owner": "미정",
      "task": "README 설치 단계를 목요일까지 가능하면 검토한다.",
      "due": "목요일까지 가능하면",
      "status": "담당자 미지정",
      "source_certainty": "부분 확정"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 스모크 테스트 통과 여부와 공유 시점",
      "스모크 결과 이후 tarball 경로 검증 필요 여부",
      "Doyun의 failure triage note 작성 완료 여부",
      "README 설치 단계 검토 담당자 지정 여부",
      "최종 릴리스 승인 권한자 결정 여부",
      "릴리스 노트에 내부 수요일 목표를 언급할지에 대한 결정 여부"
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "명시되지 않은 추가 담당자",
      "명시되지 않은 추가 마감일"
    ]
  },
  "non_invention_rules": [
    "고객, 예산, 보안, 장애, 법무 관련 사실은 언급된 범위를 넘어서 추가하지 않는다.",
    "확정되지 않은 승인자, 담당자, 마감일은 추정하지 않는다.",
    "수요일 릴리스는 확정 일정이 아니라 내부 스트레치 목표로만 기록한다.",
    "거절된 제안은 결정 사항처럼 표현하지 않는다.",
    "README 검토는 제안 수준이므로 확정 액션처럼 과장하지 않는다."
  ]
}
